using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ──────────────────────────────────────────────
    //  CalculateTotal – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price yields zero total")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity yields zero total")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    // ──────────────────────────────────────────────
    //  CalculateTotal – invalid input DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1, 0.1, "unitPrice", DisplayName = "Negative unit price throws")]
    [DataRow(10.0, -1, 0.1, "quantity",  DisplayName = "Negative quantity throws")]
    [DataRow(10.0, 1, -0.1, "taxRate",   DisplayName = "Negative tax rate throws")]
    [DataRow(10.0, 1, 1.5,  "taxRate",   DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    // ──────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (method source)
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> DiscountTestCases =>
    [
        [100.00m, 0m,     100.00m, "No discount"],
        [100.00m, 10m,    90.00m,  "10% discount"],
        [100.00m, 50m,    50.00m,  "Half-price discount"],
        [100.00m, 100m,   0.00m,   "100% discount (free)"],
        [250.75m, 20m,    200.60m, "Fractional price, 20% off"],
        [0.00m,   50m,    0.00m,   "Zero price stays zero"],
        [9.99m,   33.33m, 6.66m,   "Precise fractional discount"],
    ];

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases))]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, Math.Round(result, 2), $"Failed for scenario: {scenario}");
    }

    // ──────────────────────────────────────────────
    //  ApplyDiscount – invalid discount percentages
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0,  DisplayName = "Negative discount throws")]
    [DataRow(100.1, DisplayName = "Discount > 100 throws")]
    [DataRow(200.0, DisplayName = "Grossly over 100 throws")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ──────────────────────────────────────────────
    //  FormatPrice – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99",  DisplayName = "Default USD symbol")]
    [DataRow(19.99, "€", "€19.99",  DisplayName = "Euro symbol")]
    [DataRow(5.00,  "£", "£5.00",   DisplayName = "Pound, trailing zeros")]
    [DataRow(0.00,  "$", "$0.00",   DisplayName = "Zero price formatted")]
    public void FormatPrice_ReturnsCorrectString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

